    Object.keys(costosMap).forEach(c => {
      costoPromedioMap[c] = costosMap[c].total / costosMap[c].count;
    });

    // ID-based grouping for transaction count (one sale = one ID)
    const ventasIDset = new Set();

    for (let i = 1; i < datosVentas.length; i++) {
      const row = datosVentas[i];
      if (!row[0] || !row[1]) continue;

      let fecha;
      try {
        fecha = new Date(row[1]);
        if (isNaN(fecha.getTime())) continue;
      } catch (e) { continue; }

      const vendedor = (row[4] || 'Sin vendedor').toString().trim();
      const total = Number(row[9]) || 0;
      const envio = Number(row[8]) || 0;
      const itemText = (row[6] || '').toString();
      const canal = (row[14] || 'No especificado').toString().trim();

      // Acumular envíos
      totalEnvios += envio;
      if (fecha.getMonth() === mesActual && fecha.getFullYear() === anoActual) {
        totalEnviosMes += envio;
      }

      // Calcular costos (COGS) para márgen
      const itemsParsed = parsearItems(itemText);
      for (const it of itemsParsed) {
        costosTotales += (costoPromedioMap[it.codigo] || 0) * it.cantidad;
      }
      const fechaStr = Utilities.formatDate(fecha, tz, 'yyyy-MM-dd');
      const mesStr = Utilities.formatDate(fecha, tz, 'yyyy-MM');
      const dow = DOW_NAMES[fecha.getDay()];

      vendedoresSet.add(vendedor);
      mesesSet.add(mesStr);
      totalGeneral += total;

      // Transaction count based on unique ID
      const idVenta = row[0].toString();
      if (!ventasIDset.has(idVenta)) {
        ventasIDset.add(idVenta);
        totalTransacciones++;
      }

      // vendedores_mes
      const vmKey = mesStr + '|' + vendedor;
      if (!vendedorMesMap[vmKey]) vendedorMesMap[vmKey] = { mes: mesStr, vendedor: vendedor, total: 0, ventas: 0 };
      vendedorMesMap[vmKey].total += total;
      vendedorMesMap[vmKey].ventas++;

      // ventas_dia
      if (!ventasDiaMap[fechaStr]) ventasDiaMap[fechaStr] = { fecha: fechaStr, total: 0, ventas: 0 };
      ventasDiaMap[fechaStr].total += total;
      ventasDiaMap[fechaStr].ventas++;

      // ventas_dia_semana
      if (!ventasDiaSemanaMap[dow]) ventasDiaSemanaMap[dow] = { DiaSemana: dow, total: 0, ventas: 0 };
      ventasDiaSemanaMap[dow].total += total;
      ventasDiaSemanaMap[dow].ventas++;

      // ventas_mes
      if (!ventasMesMap[mesStr]) ventasMesMap[mesStr] = { mes: mesStr, total: 0, ventas: 0 };
      ventasMesMap[mesStr].total += total;
      ventasMesMap[mesStr].ventas++;

      // Parse items for product stats
      const items = parsearItems(itemText);
      for (const item of items) {
        const code = item.codigo;
        if (!productoQtyMap[code]) productoQtyMap[code] = 0;
        productoQtyMap[code] += item.cantidad;

        const pvKey = vendedor + '|' + code;
        if (!prodVendMap[pvKey]) prodVendMap[pvKey] = { vendedor: vendedor, producto: code, cantidad: 0 };
        prodVendMap[pvKey].cantidad += item.cantidad;
      }

      // ventas por canal
      if (!canalMap[canal]) canalMap[canal] = { canal: canal, monto: 0, cantidad: 0 };
      canalMap[canal].monto += total;
      canalMap[canal].cantidad++;
    }

    //  2) Build vendedores_mes array 
    const vendedores_mes = Object.values(vendedorMesMap).sort((a, b) => {
      if (a.mes !== b.mes) return a.mes.localeCompare(b.mes);
      return a.vendedor.localeCompare(b.vendedor);
    });

    // Round totals
    vendedores_mes.forEach(r => { r.total = Math.round(r.total * 100) / 100; });

    //  3) Build top_productos 
    const top_productos = Object.keys(productoQtyMap)
      .map(code => ({ producto: code, cantidad: productoQtyMap[code] }))
      .sort((a, b) => b.cantidad - a.cantidad)
      .slice(0, 15);

    //  4) Build productos_vendedor 
    const productos_vendedor = Object.values(prodVendMap)
      .sort((a, b) => a.vendedor.localeCompare(b.vendedor) || b.cantidad - a.cantidad);

    //  5) Build ventas_dia 
    const ventas_dia = Object.values(ventasDiaMap).sort((a, b) => a.fecha.localeCompare(b.fecha));
    ventas_dia.forEach(d => { d.total = Math.round(d.total * 100) / 100; });

    //  6) Build ventas_dia_semana (ordered MonSun) 
    const dowOrder = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
    const ventas_dia_semana = dowOrder
      .filter(d => ventasDiaSemanaMap[d])
      .map(d => {
        const v = ventasDiaSemanaMap[d];
        return { DiaSemana: v.DiaSemana, total: Math.round(v.total * 100) / 100, ventas: v.ventas };
      });

    //  7) Build top_dias 
    const top_dias = Object.values(ventasDiaMap)
      .sort((a, b) => b.total - a.total)
      .slice(0, 10)
      .map(d => ({ fecha: d.fecha, total: Math.round(d.total * 100) / 100, ventas: d.ventas }));

    //  8) Build ventas_mes 
    const meses = Array.from(mesesSet).sort();
    const ventas_mes = meses.map(m => {
      const v = ventasMesMap[m] || { total: 0, ventas: 0 };
      return { mes: m, total: Math.round(v.total * 100) / 100, ventas: v.ventas };
    });

    //  9) vendedores list 
    const vendedores = Array.from(vendedoresSet).sort();

    //  10) Best seller & best day for header KPIs 
    const vendTotals = {};
    vendedores_mes.forEach(r => {
      if (!vendTotals[r.vendedor]) vendTotals[r.vendedor] = 0;
      vendTotals[r.vendedor] += r.total;
    });
    let bestVendor = '', bestVendorTotal = 0;
    Object.keys(vendTotals).forEach(v => {
      if (vendTotals[v] > bestVendorTotal) { bestVendor = v; bestVendorTotal = vendTotals[v]; }
    });

    const bestDay = top_dias.length > 0 ? top_dias[0] : { fecha: '-', total: 0, ventas: 0 };

    // Determine period label
    const periodoLabel = meses.length > 0
      ? _mesCorto(meses[0]) + ' - ' + _mesCorto(meses[meses.length - 1])
      : 'Sin datos';

    //  11) Inventory summary 
    let totalPiezas = 0;
    let valorInventario = 0;
    const stockMap = {};  // code  {nombre, stock, precio, stockMin, grupo}

    for (let i = 1; i < datosInventario.length; i++) {
      const code = (datosInventario[i][0] || '').toString().trim();
      const cantidad = Number(datosInventario[i][2]) || 0;
      const costo = Number(datosInventario[i][4]) || 0;
      const precio = Number(datosInventario[i][5]) || 0;
      const ubicacion = (datosInventario[i][6] || '').toString().trim();

      totalPiezas += cantidad;
      valorInventario += cantidad * precio;

      if (code) {
        if (!stockMap[code]) stockMap[code] = { codigo: code, nombre: '', stock: 0, precio: precio, stockMin: 0, grupo: '' };
        stockMap[code].stock += cantidad;
      }
    }

    // Enrich from Productos sheet
    for (let i = 1; i < datosProductos.length; i++) {
      const code = (datosProductos[i][0] || '').toString().trim();
      const nombre = (datosProductos[i][1] || '').toString();
      const grupo = (datosProductos[i][3] || '').toString();
      const stockMin = Number(datosProductos[i][4]) || 0;
      const precio = Number(datosProductos[i][5]) || 0;

      if (stockMap[code]) {
        stockMap[code].nombre = nombre;
        stockMap[code].grupo = grupo;
        stockMap[code].stockMin = stockMin;
        if (precio > 0) stockMap[code].precio = precio;
      } else {
        stockMap[code] = { codigo: code, nombre: nombre, stock: 0, precio: precio, stockMin: stockMin, grupo: grupo };
      }
    }

    const inventarioReal = Object.values(stockMap).map(p => {
      let estado = 'Normal';
      if (p.stock <= 0) estado = 'Sin Stock';
      else if (p.stock <= p.stockMin && p.stockMin > 0) estado = 'Stock Bajo';
      return {
        codigo: p.codigo, nombre: p.nombre, grupo: p.grupo,
        stock: p.stock, precio: p.precio, stockMin: p.stockMin, estado: estado
      };
    }).sort((a, b) => a.codigo.localeCompare(b.codigo));

    //  12) Finance summary 
    let ingresosMes = 0, gastosMes = 0, ingresosTot = 0, gastosTot = 0;
    const finanzasHistorial = [];

    for (let i = 1; i < datosFinanzas.length; i++) {
      const row = datosFinanzas[i];
      if (!row[0]) continue;

      const tipo = (row[2] || '').toString().trim();
      const monto = Number(row[4]) || 0;

      if (tipo === 'Ingreso') ingresosTot += monto;
      if (tipo === 'Gasto') gastosTot += monto;

      // Check if this month
      let fechaFin;
      try { fechaFin = new Date(row[1]); } catch (e) { fechaFin = null; }
      if (fechaFin && fechaFin.getMonth() === mesActual && fechaFin.getFullYear() === anoActual) {
        if (tipo === 'Ingreso') ingresosMes += monto;
        if (tipo === 'Gasto') gastosMes += monto;
      }

      finanzasHistorial.push({
        id: row[0], fecha: row[1],
        tipo: tipo, categoria: row[3],
        monto: monto, responsable: row[5],
        obs: row[6] || ''
      });
    }

    // Utilidad neta = ventas del mes - gastos del mes
    const ventasDelMes = ventas_mes.find(m => {
      const [y, mo] = m.mes.split('-');
      return parseInt(y) === anoActual && parseInt(mo) === (mesActual + 1);
    });
    const ingresosVentasMes = ventasDelMes ? ventasDelMes.total : 0;
    const utilidadNeta = Math.round((ingresosVentasMes - gastosMes) * 100) / 100;

    // KPIs adicionales: envíos, rotación, márgen
    const margenPromedio = totalGeneral > 0
      ? Math.round((totalGeneral - costosTotales) / totalGeneral * 1000) / 10
      : 0;
    const rotacionInventario = valorInventario > 0
      ? Math.round(costosTotales / valorInventario * 100) / 100
      : 0;

    //  BUILD RESULT 
    return {
      vendedores_mes: vendedores_mes,
      top_productos: top_productos,
      productos_vendedor: productos_vendedor,
      ventas_dia: ventas_dia,
      ventas_dia_semana: ventas_dia_semana,
      top_dias: top_dias,
      ventas_mes: ventas_mes,
      vendedores: vendedores,
      meses: meses,
      // Canal
      ventasPorCanal: Object.values(canalMap).sort((a, b) => b.monto - a.monto),
      // Header KPIs
      totalGeneral: Math.round(totalGeneral * 100) / 100,
      totalTransacciones: totalTransacciones,
      periodoLabel: periodoLabel,
      mejorVendedor: bestVendor,
      mejorVendedorTotal: Math.round(bestVendorTotal * 100) / 100,
      mejorDia: bestDay,
      // Envíos, Rotación, Márgen
      totalEnvios: Math.round(totalEnvios * 100) / 100,
      totalEnviosMes: Math.round(totalEnviosMes * 100) / 100,
      margenPromedio: margenPromedio,
      rotacionInventario: rotacionInventario,
      // Inventory
      inventario: { totalPiezas: totalPiezas, valorTotal: Math.round(valorInventario * 100) / 100 },
      inventarioReal: inventarioReal,
      // Finance
      finanzas: {
        ingresosMes: Math.round(ingresosMes * 100) / 100,
        gastosMes: Math.round(gastosMes * 100) / 100,
        utilidadNeta: utilidadNeta,
        ingresosTot: Math.round(ingresosTot * 100) / 100,
        gastosTot: Math.round(gastosTot * 100) / 100
      },
      finanzasHistorial: finanzasHistorial
    };

  } catch (error) {
    console.error(' Error en obtenerDatosDashboardBackend:', error);
    Logger.log('Error stack: ' + error.stack);
    return _dashboardVacio();
  }
}

/** Helper: short month label "Nov 25" from "2025-11" */
function _mesCorto(mesStr) {
  const mNames = ['Ene','Feb','Mar','Abr','May','Jun','Jul','Ago','Sep','Oct','Nov','Dic'];
  const [y, m] = mesStr.split('-');
  return mNames[parseInt(m) - 1] + ' ' + y.slice(2);
}

/** Empty dashboard data fallback */
function _dashboardVacio() {
  return {
    vendedores_mes: [], top_productos: [], productos_vendedor: [],
    ventas_dia: [], ventas_dia_semana: [], top_dias: [],
    ventas_mes: [], vendedores: [], meses: [],
    totalGeneral: 0, totalTransacciones: 0, periodoLabel: 'Sin datos',
    mejorVendedor: '-', mejorVendedorTotal: 0,
    mejorDia: { fecha: '-', total: 0, ventas: 0 },
    inventario: { totalPiezas: 0, valorTotal: 0 },
    inventarioReal: [],
    finanzas: { ingresosMes: 0, gastosMes: 0, utilidadNeta: 0, ingresosTot: 0, gastosTot: 0 },
    finanzasHistorial: []
  };
}

function registrarMovimientoFinanciero(datos) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    let hojaFinanzas = ss.getSheetByName(HOJA_FINANZAS);

    // Si no existe la hoja, crearla con encabezados
    if (!hojaFinanzas) {
      hojaFinanzas = ss.insertSheet(HOJA_FINANZAS);
      const encabezados = [[
        "ID_Movimiento",
        "Fecha",
        "Tipo",
        "Categoría",
        "Monto",
        "Responsable",
        "Observaciones"
      ]];
      hojaFinanzas.getRange(1, 1, 1, 7).setValues(encabezados);
      hojaFinanzas.getRange(1, 1, 1, 7)
        .setBackground("#28a745")
        .setFontColor("white")
        .setFontWeight("bold");
      hojaFinanzas.setFrozenRows(1);
      hojaFinanzas.autoResizeColumns(1, 7);
    }

    // ========================================
    // VALIDACIONES
    // ========================================
    if (!datos.tipo || (datos.tipo !== "Ingreso" && datos.tipo !== "Gasto")) {
      return { success: false, message: "❌ El tipo de movimiento es obligatorio (Ingreso o Gasto)." };
    }

    if (!datos.categoria) {
      return { success: false, message: "❌ La categoría es obligatoria." };
    }

    const monto = parseFloat(datos.monto);
    if (isNaN(monto) || monto <= 0) {
      return { success: false, message: "❌ El monto debe ser un número mayor a 0." };
    }

    if (!datos.responsable) {
      return { success: false, message: "❌ El responsable es obligatorio." };
    }

    if (!datos.fecha) {
      return { success: false, message: "❌ La fecha es obligatoria." };
    }

    // ========================================
    // GENERAR ID ÚNICO
    // ========================================
    const timestamp = new Date();
    const idMovimiento = "FIN-" + Utilities.formatDate(timestamp, Session.getScriptTimeZone(), "yyyyMMdd-HHmmss");

    // ========================================
    // GUARDAR EN LA HOJA
    // ========================================
    hojaFinanzas.appendRow([
      idMovimiento,
      datos.fecha,
      datos.tipo,
      datos.categoria,
      monto,               // Se guarda como número
      datos.responsable,
      datos.observaciones || ""
    ]);

    Logger.log("✅ Movimiento financiero registrado: " + idMovimiento);

    // ========================================
    // RESPUESTA EXITOSA
    // ========================================
    const emoji = datos.tipo === "Ingreso" ? "📈" : "📉";

    return {
      success: true,
      message: `✅ Movimiento financiero registrado exitosamente.\n\n` +
               `📋 ID: ${idMovimiento}\n` +
               `📅 Fecha: ${datos.fecha}\n` +
               `${emoji} Tipo: ${datos.tipo}\n` +
               `🏷️ Categoría: ${datos.categoria}\n` +
               `💰 Monto: $${monto.toFixed(2)}\n` +
               `👤 Responsable: ${datos.responsable}\n` +
               (datos.observaciones ? `📝 Observaciones: ${datos.observaciones}` : "")
    };

  } catch (error) {
    console.error("❌ Error en registrarMovimientoFinanciero:", error);
    Logger.log("Error stack: " + error.stack);
    return {
      success: false,
      message: `❌ Error del sistema: ${error.message}\n\nEl movimiento NO ha sido registrado.`
    };
  }
}

/**
 * Servicio de Importación Masiva de Inventario
 * Realiza sincronización completa: Productos + Movimientos + Inventario
 */

/**
 * Importa inventario masivamente desde datos CSV con sincronización completa
 * @param {Array<Array<string>>} csvData - Array bidimensional con datos del CSV
 * @returns {Object} Resumen de la importación con estadísticas
 */
function importarInventarioMasivo(csvData) {
  const lock = LockService.getScriptLock();

  try {
    lock.waitLock(30000);
    Logger.log("🚀 Iniciando importación masiva con sincronización completa...");

    if (!csvData || !Array.isArray(csvData) || csvData.length === 0) {
      return { success: false, error: "❌ No se recibieron datos válidos." };
    }

    // Mapeo de columnas (delimitador: punto y coma)
    const COL = {
      NOMBRE: 0, CANTIDAD_DYLAN: 2, CANTIDAD_LUDEN: 3, CANTIDAD_JEAN: 4,
      CODIGO: 5, COSTO: 6, PRECIO: 7
    };

    const ALMACENES = [
      { nombre: "Casa Dylan", col: COL.CANTIDAD_DYLAN, key: 'DYLAN' },
      { nombre: "Casa Luden", col: COL.CANTIDAD_LUDEN, key: 'LUDEN' },
      { nombre: "Casa Jean", col: COL.CANTIDAD_JEAN, key: 'JEAN' }
    ];

    // Estadísticas
    const stats = {
      productosCreados: 0, productosActualizados: 0,
      unidadesDylan: 0, unidadesLuden: 0, unidadesJean: 0,
      errores: [], filasProcesadas: 0
    };

    // === OPTIMIZACIÓN: Cargar datos en memoria ===
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaProductos = ss.getSheetByName(HOJA_PRODUCTOS);
    const hojaInventario = ss.getSheetByName(HOJA_INVENTARIO);
    const hojaMovimientos = ss.getSheetByName(HOJA_MOVIMIENTOS);

    if (!hojaProductos || !hojaInventario || !hojaMovimientos) {
      return { success: false, error: "❌ Faltan hojas del sistema. Inicialice primero." };
    }

    // Cargar productos existentes en un mapa { "SKU": fila }
    const datosProductos = hojaProductos.getDataRange().getValues();
    const mapaProductos = {};
    for (let i = 1; i < datosProductos.length; i++) {
      const sku = datosProductos[i][0] ? datosProductos[i][0].toString().trim().toUpperCase() : '';
      if (sku) mapaProductos[sku] = i + 1; // Guardar número de fila
    }

    // Cargar inventario existente en un mapa { "SKU|ALMACEN": fila }
    const datosInventario = hojaInventario.getDataRange().getValues();
    const headersInv = datosInventario[0];
    const colInvCodigo = headersInv.findIndex(h => h.toString().toLowerCase().includes('codigo'));
    const colInvUbicacion = headersInv.findIndex(h => h.toString().toLowerCase().includes('ubicacion'));
    const colInvCantidad = headersInv.findIndex(h => h.toString().toLowerCase().includes('cantidad'));
    const colInvNombre = headersInv.findIndex(h => h.toString().toLowerCase().includes('nombre'));
    const colInvPrecio = headersInv.findIndex(h => h.toString().toLowerCase().includes('precio'));
    const colInvCosto = headersInv.findIndex(h => h.toString().toLowerCase().includes('costo'));
    const colInvFecha = headersInv.findIndex(h => h.toString().toLowerCase().includes('fecha'));

    const mapaInventario = {};
    for (let i = 1; i < datosInventario.length; i++) {
      const sku = datosInventario[i][colInvCodigo] ? datosInventario[i][colInvCodigo].toString().trim().toUpperCase() : '';
      const ubicacion = datosInventario[i][colInvUbicacion] ? datosInventario[i][colInvUbicacion].toString().trim() : '';
      if (sku && ubicacion) {
        const clave = `${sku}|${ubicacion}`;
        mapaInventario[clave] = {
          fila: i + 1,
          cantidadActual: Number(datosInventario[i][colInvCantidad]) || 0
        };
      }
    }

    // Arrays para batch updates
    const productosNuevos = [];
    const movimientosNuevos = [];
    const inventarioNuevo = [];
    const inventarioActualizar = [];

    // Buscar primera fila con datos válidos
    let primeraFilaDatos = -1;
    for (let i = 0; i < csvData.length; i++) {
      if (csvData[i][COL.CODIGO] && csvData[i][COL.CODIGO].toString().trim() !== '') {
        primeraFilaDatos = i;
        Logger.log(`✅ Primera fila de datos en índice ${i}`);
        break;
      }
    }

    if (primeraFilaDatos === -1) {
      return { success: false, error: "❌ No se encontraron datos válidos en el CSV." };
    }

    // === PROCESAR CADA FILA ===
    for (let i = primeraFilaDatos; i < csvData.length; i++) {
      const fila = csvData[i];

      try {
        const codigo = fila[COL.CODIGO] ? fila[COL.CODIGO].toString().trim().toUpperCase() : '';
        const nombre = fila[COL.NOMBRE] ? fila[COL.NOMBRE].toString().trim() : '';
        const costo = parseFloat(fila[COL.COSTO]) || 0;
        const precio = parseFloat(fila[COL.PRECIO]) || 0;

        // Saltar filas de categorías (sin código SKU)
        if (!codigo || codigo === '') {
          Logger.log(`⚠️ Fila ${i + 1}: Sin código SKU. Saltando...`);
          continue;
        }

        if (!nombre || precio <= 0) {
          Logger.log(`⚠️ Fila ${i + 1}: Datos incompletos. Saltando...`);
          continue;
        }

        Logger.log(`📦 Procesando: ${codigo} - ${nombre}`);

        // === 1. GESTIÓN DE PRODUCTO ===
        if (!mapaProductos[codigo]) {
          // Producto nuevo: agregar a batch
          productosNuevos.push([codigo, nombre, "Unidad", "General", 5, precio, new Date()]);
          mapaProductos[codigo] = true; // Marcar como existente en memoria
          stats.productosCreados++;
          Logger.log(`  ➕ Producto nuevo: ${codigo}`);
        } else {
          // Producto existente: actualizar precio si cambió
          const filaProducto = mapaProductos[codigo];
          if (typeof filaProducto === 'number') {
            hojaProductos.getRange(filaProducto, 6).setValue(precio);
          }
          stats.productosActualizados++;
          Logger.log(`  ✏️ Producto existente: ${codigo}`);
        }

        // === 2. DISTRIBUCIÓN MULTI-ALMACÉN ===
        const fechaHoy = Utilities.formatDate(new Date(), Session.getScriptTimeZone(), "yyyy-MM-dd");
        const timestamp = new Date();

        for (const almacen of ALMACENES) {
          const cantidad = parseFloat(fila[almacen.col]) || 0;

          if (cantidad > 0) {
            Logger.log(`  📍 ${almacen.nombre}: ${cantidad} unidades`);

            // === A. REGISTRAR MOVIMIENTO ===
            const stockActual = calcularStock(codigo); // Calcular stock antes del movimiento
            movimientosNuevos.push([
              codigo,
              timestamp,
              TIPOS_MOVIMIENTO.INGRESO,
              cantidad,
              Session.getActiveUser().getEmail() || "Sistema",
              timestamp,
              `Importación masiva CSV - ${nombre}`,
              stockActual + cantidad,
              almacen.nombre
            ]);

            // === B. ACTUALIZAR INVENTARIO ===
            const claveInv = `${codigo}|${almacen.nombre}`;

            if (mapaInventario[claveInv]) {
              // Ya existe: sumar cantidad
              const info = mapaInventario[claveInv];
              const nuevaCantidad = info.cantidadActual + cantidad;
              inventarioActualizar.push({
                fila: info.fila,
                cantidad: nuevaCantidad
              });
              mapaInventario[claveInv].cantidadActual = nuevaCantidad; // Actualizar en memoria
              Logger.log(`    ✅ Inventario actualizado: ${info.cantidadActual} + ${cantidad} = ${nuevaCantidad}`);
            } else {
              // No existe: crear nueva entrada
              inventarioNuevo.push([
                codigo,
                nombre,
                cantidad,
                "",  // descripción
                costo,
                precio,
                almacen.nombre,
                timestamp
              ]);
              mapaInventario[claveInv] = { cantidadActual: cantidad }; // Agregar a memoria
              Logger.log(`    ➕ Nueva entrada en inventario: ${cantidad} unidades`);
            }

            // Sumar a estadísticas
            if (almacen.key === 'DYLAN') stats.unidadesDylan += cantidad;
            if (almacen.key === 'LUDEN') stats.unidadesLuden += cantidad;
            if (almacen.key === 'JEAN') stats.unidadesJean += cantidad;
          }
        }

        stats.filasProcesadas++;

      } catch (errorFila) {
        Logger.log(`❌ Error en fila ${i + 1}: ${errorFila.message}`);
        stats.errores.push(`Fila ${i + 1}: ${errorFila.message}`);
      }
    }

    // === ESCRIBIR TODOS LOS CAMBIOS EN BATCH ===
    Logger.log("💾 Escribiendo cambios en batch...");

    // Productos nuevos
    if (productosNuevos.length > 0) {
      const ultimaFilaProductos = hojaProductos.getLastRow() + 1;
      hojaProductos.getRange(ultimaFilaProductos, 1, productosNuevos.length, 7)
        .setValues(productosNuevos);
      Logger.log(`✅ ${productosNuevos.length} productos nuevos escritos`);
    }

    // Movimientos nuevos
    if (movimientosNuevos.length > 0) {
      const ultimaFilaMov = hojaMovimientos.getLastRow() + 1;
      hojaMovimientos.getRange(ultimaFilaMov, 1, movimientosNuevos.length, 9)
        .setValues(movimientosNuevos);
      Logger.log(`✅ ${movimientosNuevos.length} movimientos registrados`);
    }

    // Inventario nuevo
    if (inventarioNuevo.length > 0) {
      const ultimaFilaInv = hojaInventario.getLastRow() + 1;
      hojaInventario.getRange(ultimaFilaInv, 1, inventarioNuevo.length, 8)
        .setValues(inventarioNuevo);
      Logger.log(`✅ ${inventarioNuevo.length} nuevas entradas en inventario`);
    }

    // Inventario actualizar
    if (inventarioActualizar.length > 0) {
      for (const update of inventarioActualizar) {
        hojaInventario.getRange(update.fila, colInvCantidad + 1).setValue(update.cantidad);
        hojaInventario.getRange(update.fila, colInvFecha + 1).setValue(new Date());
      }
      Logger.log(`✅ ${inventarioActualizar.length} entradas de inventario actualizadas`);
    }

    Logger.log("✅ Importación completada");
    Logger.log(`📊 Estadísticas: ${JSON.stringify(stats)}`);

    return { success: true, stats: stats };

  } catch (error) {
    Logger.log(`❌ Error general: ${error.message}`);
    Logger.log(`Stack: ${error.stack}`);
    return { success: false, error: `❌ Error al procesar: ${error.message}` };
  } finally {
    lock.releaseLock();
  }
}

function insertarProductoConUbicacion(datos) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaEntrada = ss.getSheetByName(HOJA_ENTRADA);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    const hojaProductos = ss.getSheetByName(HOJA_PRODUCTOS);
    
    if (!hojaEntrada || !hojaInv || !hojaProductos) {
      throw new Error("Las hojas requeridas no existen. Por favor, inicialice el sistema primero desde Configuración.");
    }

    const codigo = datos.codigo.toString().trim().toUpperCase();
    const cantidad = parseFloat(datos.cantidad);
    const costo = parseFloat(datos.costo) || 0;
    const precio = parseFloat(datos.precio);
    const almacen = datos.almacen.toString().trim();
    const nombre = datos.nombre.toString().trim();
    const unidad = datos.unidad || "Unidades";
    const grupo = datos.grupo || "General";
    const stockMin = Math.max(0, parseInt(datos.stockMin) || 0);
    const descripcion = datos.descripcion ? datos.descripcion.toString().trim() : "";
    const fechaHora = new Date();

    // Validaciones
    if (!codigo || !nombre || !almacen || cantidad <= 0 || precio <= 0) {
      return "❌ Código, nombre, cantidad, precio y almacén son obligatorios.";
    }

    Logger.log(`📦 Insertando producto: ${codigo} - ${nombre} - Cantidad: ${cantidad} - Ubicación: ${almacen}`);

    // Verificar si existe el producto en Productos
    let productoExiste = false;
    const datosProductos = hojaProductos.getDataRange().getValues();
    
    for (let i = 1; i < datosProductos.length; i++) {
      if (datosProductos[i][0] && datosProductos[i][0].toString().trim().toUpperCase() === codigo) {
        productoExiste = true;
        Logger.log(`✅ Producto ${codigo} ya existe en Productos`);
        break;
      }
    }

    // Si no existe, registrarlo automáticamente
    if (!productoExiste) {
      Logger.log(`➕ Registrando nuevo producto en Productos: ${codigo}`);
      const resultado = registrarProducto({
        codigo: codigo,
        nombre: nombre,
        unidad: unidad,
        grupo: grupo,
        stockMin: stockMin,
        precio: precio
      });
      
      if (!resultado.includes("correctamente")) {
        return resultado;
      }
    }

    // === ACTUALIZAR HOJA ENTRADA ===
    Logger.log("📝 Actualizando Hoja Entrada...");
    const headersEntrada = hojaEntrada.getRange(14, 1, 1, hojaEntrada.getLastColumn()).getValues()[0];
    const colEntrada = {};
    headersEntrada.forEach((h, i) => colEntrada[h.trim().toLowerCase()] = i + 1);

    const datosEntrada = hojaEntrada.getDataRange().getValues();
    let filaEntradaExistente = null;

    for (let i = 14; i < datosEntrada.length; i++) {
      const codEntrada = datosEntrada[i][colEntrada['codigo unico del producto'] - 1]?.toString().trim();
      if (codEntrada === codigo) {
        filaEntradaExistente = i + 1;
        break;
      }
    }

    if (filaEntradaExistente) {
      const cantidadActual = Number(hojaEntrada.getRange(filaEntradaExistente, colEntrada['cantidad de entrada del producto']).getValue()) || 0;
      hojaEntrada.getRange(filaEntradaExistente, colEntrada['cantidad de entrada del producto']).setValue(cantidadActual + cantidad);
      hojaEntrada.getRange(filaEntradaExistente, colEntrada['precio']).setValue(precio);
      hojaEntrada.getRange(filaEntradaExistente, colEntrada['costo']).setValue(costo);
      hojaEntrada.getRange(filaEntradaExistente, colEntrada['fecha y hora']).setValue(fechaHora);
      Logger.log(`✅ Actualizada entrada existente en fila ${filaEntradaExistente}`);
    } else {
      const nuevaFila = hojaEntrada.getLastRow() + 1;
      hojaEntrada.getRange(nuevaFila, colEntrada['codigo unico del producto']).setValue(codigo);
      hojaEntrada.getRange(nuevaFila, colEntrada['nombre del producto']).setValue(nombre);
      hojaEntrada.getRange(nuevaFila, colEntrada['cantidad de entrada del producto']).setValue(cantidad);
      hojaEntrada.getRange(nuevaFila, colEntrada['descripción del producto']).setValue(descripcion);
      hojaEntrada.getRange(nuevaFila, colEntrada['costo']).setValue(costo);
      hojaEntrada.getRange(nuevaFila, colEntrada['precio']).setValue(precio);
      hojaEntrada.getRange(nuevaFila, colEntrada['fecha y hora']).setValue(fechaHora);
      Logger.log(`✅ Nueva entrada creada en fila ${nuevaFila}`);
    }

    // === ACTUALIZAR INVENTARIO POR UBICACIÓN ===
    Logger.log("📍 Actualizando Inventario por ubicación...");
    const headersInv = hojaInv.getRange(1, 1, 1, hojaInv.getLastColumn()).getValues()[0];
    const colInv = {};
    headersInv.forEach((h, i) => colInv[h.trim().toLowerCase()] = i + 1);
    
    Logger.log("Columnas Inventario: " + JSON.stringify(colInv));

    // Verificar que existan las columnas necesarias
    if (!colInv['ubicacion del producto']) {
      throw new Error("❌ La hoja Inventario no tiene la columna 'ubicacion del producto'. Reinicialice el sistema.");
    }

    const datosInv = hojaInv.getDataRange().getValues();
    let filaInvExistente = null;

    for (let i = 1; i < datosInv.length; i++) {
      const codInv = datosInv[i][colInv['codigo unico del producto'] - 1]?.toString().trim();
      const ubInv = datosInv[i][colInv['ubicacion del producto'] - 1]?.toString().trim();

      if (codInv === codigo && ubInv === almacen) {
        filaInvExistente = i + 1;
        Logger.log(`✅ Encontrada ubicación existente: Fila ${filaInvExistente} - ${almacen}`);
        break;
      }
    }

    if (filaInvExistente) {
      const stockActual = Number(hojaInv.getRange(filaInvExistente, colInv['cantidad de entrada del producto']).getValue()) || 0;
      hojaInv.getRange(filaInvExistente, colInv['cantidad de entrada del producto']).setValue(stockActual + cantidad);
      hojaInv.getRange(filaInvExistente, colInv['precio']).setValue(precio);
      hojaInv.getRange(filaInvExistente, colInv['costo']).setValue(costo);
      hojaInv.getRange(filaInvExistente, colInv['fecha y hora']).setValue(fechaHora);
      Logger.log(`✅ Stock actualizado en ${almacen}: ${stockActual} + ${cantidad} = ${stockActual + cantidad}`);
    } else {
      const nuevaFilaInv = hojaInv.getLastRow() + 1;
      hojaInv.getRange(nuevaFilaInv, colInv['codigo unico del producto']).setValue(codigo);
      hojaInv.getRange(nuevaFilaInv, colInv['nombre del producto']).setValue(nombre);
      hojaInv.getRange(nuevaFilaInv, colInv['cantidad de entrada del producto']).setValue(cantidad);
      hojaInv.getRange(nuevaFilaInv, colInv['precio']).setValue(precio);
      hojaInv.getRange(nuevaFilaInv, colInv['costo']).setValue(costo);
      hojaInv.getRange(nuevaFilaInv, colInv['ubicacion del producto']).setValue(almacen);
      hojaInv.getRange(nuevaFilaInv, colInv['descripción del producto']).setValue(descripcion);
      hojaInv.getRange(nuevaFilaInv, colInv['fecha y hora']).setValue(fechaHora);
      Logger.log(`✅ Nueva ubicación creada en fila ${nuevaFilaInv}: ${almacen} con ${cantidad} unidades`);
    }

    // === REGISTRAR MOVIMIENTO ===
    Logger.log("📊 Registrando movimiento...");
    registrarMovimiento({
      codigo: codigo,
      fecha: Utilities.formatDate(fechaHora, Session.getScriptTimeZone(), "yyyy-MM-dd"),
      tipo: TIPOS_MOVIMIENTO.INGRESO,
      cantidad: cantidad,
      ubicacion: almacen,
      observaciones: `Ingreso a ${almacen}. ${descripcion}`
    });

    Logger.log(`✅ Proceso completado exitosamente para ${codigo} en ${almacen}`);
    return `✅ Producto ${productoExiste ? 'actualizado' : 'creado y registrado'} correctamente.\n📍 Ubicación: ${almacen}\n📦 Cantidad: ${cantidad} ${unidad}`;

  } catch (error) {
    console.error("❌ Error en insertarProductoConUbicacion:", error);
    Logger.log("Error stack: " + error.stack);
    return `❌ Error: ${error.message}`;
  }
}

function registrarMovimiento(mov) {
  try {
    if (!mov || !mov.codigo || !mov.fecha || !mov.tipo || !mov.cantidad) {
      return "Datos del movimiento incompletos.";
    }

    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const prodSheet = ss.getSheetByName(HOJA_PRODUCTOS);
    const movSheet = ss.getSheetByName(HOJA_MOVIMIENTOS);
    
    if (!prodSheet || !movSheet) {
      throw new Error("Las hojas del sistema no existen. Inicialice el sistema primero.");
    }
    
    if (!movSheet.getLastRow()) {
      movSheet.getRange(1, 1, 1, 9).setValues([["Código", "Fecha", "Tipo", "Cantidad", "Usuario", "Timestamp", "Observaciones", "Stock Resultante", "Ubicación"]]);
      movSheet.getRange(1, 1, 1, 9).setBackground("#5DADE2").setFontColor("white").setFontWeight("bold");
    }
    
    const codigoNormalizado = mov.codigo.toString().trim().toUpperCase();
    const cantidad = parseFloat(mov.cantidad);
    const tipo = mov.tipo.toString().toUpperCase();
    
    if (cantidad <= 0) {
      return "La cantidad debe ser mayor a 0.";
    }
    
    if (!Object.values(TIPOS_MOVIMIENTO).includes(tipo)) {
      return `Tipo de movimiento inválido: ${tipo}`;
    }
    
    const productos = prodSheet.getDataRange().getValues();
    let productoExiste = false;
    
    for (let i = 1; i < productos.length; i++) {
      if (productos[i][0] && productos[i][0].toString().trim().toUpperCase() === codigoNormalizado) {
        productoExiste = true;
        break;
      }
    }
    
    if (!productoExiste) {
      return "El producto no existe. Regístrelo primero.";
    }
    
    const stockActual = calcularStock(codigoNormalizado);
    
    if ((tipo === TIPOS_MOVIMIENTO.SALIDA || tipo === TIPOS_MOVIMIENTO.AJUSTE_NEGATIVO || tipo === TIPOS_MOVIMIENTO.VENTA) && stockActual < cantidad) {
      return `Stock insuficiente. Disponible: ${stockActual}, Solicitado: ${cantidad}`;
    }
    
    let stockResultante = stockActual;
    switch (tipo) {
      case TIPOS_MOVIMIENTO.INGRESO:
      case TIPOS_MOVIMIENTO.AJUSTE_POSITIVO:
        stockResultante += cantidad;
        break;
      case TIPOS_MOVIMIENTO.SALIDA:
      case TIPOS_MOVIMIENTO.AJUSTE_NEGATIVO:
      case TIPOS_MOVIMIENTO.VENTA:
        stockResultante -= cantidad;
        break;
      case TIPOS_MOVIMIENTO.AJUSTE:
        stockResultante += cantidad;
        break;
    }
    
    stockResultante = Math.max(0, stockResultante);
    
    let fechaMovimiento;
    if (typeof mov.fecha === 'string') {
      const partesFecha = mov.fecha.split('-');
      fechaMovimiento = new Date(parseInt(partesFecha[0]), parseInt(partesFecha[1]) - 1, parseInt(partesFecha[2]), 12, 0, 0);
    } else {
      fechaMovimiento = new Date(mov.fecha);
    }
    
    movSheet.appendRow([
      codigoNormalizado,
      fechaMovimiento,
      tipo,
      cantidad,
      Session.getActiveUser().getEmail() || "Sistema",
      new Date(),
      mov.observaciones || "",
      stockResultante,
      mov.ubicacion || ""
    ]);
    
    return "Movimiento registrado correctamente.";
  } catch (error) {
    console.error("Error en registrarMovimiento:", error);
    return `Error al registrar movimiento: ${error.message}`;
  }
}

function buscarEnInventarioPorUbicacion(codigo) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    
    if (!hojaInv) {
      Logger.log("❌ La hoja Inventario no existe");
      return { 
        success: false,
        error: "La hoja de inventario no existe. Inicialice el sistema primero." 
      };
    }

    const datos = hojaInv.getDataRange().getValues();
    
    if (datos.length <= 1) {
      Logger.log("⚠️ La hoja Inventario está vacía");
      return { 
        success: false,
        codigo: codigo,
        coincidencias: [], 
        totalCantidad: 0, 
        totalUbicaciones: 0,
        mensaje: "⚠️ La hoja de inventario está vacía. Primero debe registrar productos con entrada."
      };
    }

    const headers = datos[0];
    const colIndex = {};
    
    headers.forEach((h, i) => {
      if (h) {
        const headerNorm = h.toString().toLowerCase().trim();
        colIndex[headerNorm] = i;
      }
    });
    
    Logger.log("📋 Encabezados encontrados en Inventario: " + JSON.stringify(colIndex));
    
    const columnasRequeridas = ['codigo unico del producto', 'cantidad de entrada del producto', 'ubicacion del producto'];
    const columnasFaltantes = columnasRequeridas.filter(col => colIndex[col] === undefined);
    
    if (columnasFaltantes.length > 0) {
      Logger.log(`❌ Faltan columnas: ${columnasFaltantes.join(', ')}`);
      return { 
        success: false,
        error: `❌ Faltan columnas en la hoja Inventario: ${columnasFaltantes.join(', ')}. Por favor, reinicialice el sistema.` 
      };
    }
    
    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    const coincidencias = [];
    let totalCantidad = 0;

    Logger.log(`🔍 Buscando código: ${codigoNormalizado} en ${datos.length - 1} filas`);

    for (let i = 1; i < datos.length; i++) {
      const fila = datos[i];
      
      const codigoCol = colIndex['codigo unico del producto'];
      const codigoInventario = fila[codigoCol] ? fila[codigoCol].toString().trim().toUpperCase() : '';
      
      if (codigoInventario === codigoNormalizado) {
        const cantidadCol = colIndex['cantidad de entrada del producto'];
        const nombreCol = colIndex['nombre del producto'] !== undefined ? colIndex['nombre del producto'] : 1;
        const descripcionCol = colIndex['descripción del producto'] !== undefined ? colIndex['descripción del producto'] : 3;
        const costoCol = colIndex['costo'] !== undefined ? colIndex['costo'] : 4;
        const precioCol = colIndex['precio'] !== undefined ? colIndex['precio'] : 5;
        const ubicacionCol = colIndex['ubicacion del producto'];
        const fechaCol = colIndex['fecha y hora'] !== undefined ? colIndex['fecha y hora'] : 7;
        
        const cantidad = Number(fila[cantidadCol]) || 0;
        const ubicacion = fila[ubicacionCol] ? fila[ubicacionCol].toString().trim() : 'Sin ubicación';
        
        totalCantidad += cantidad;
        
        Logger.log(`✅ Encontrado en fila ${i + 1}: ${codigoInventario} - ${ubicacion} - Cantidad: ${cantidad}`);
        
        coincidencias.push({
          fila: i + 1,
          codigo: codigoInventario,
          nombre: fila[nombreCol] ? fila[nombreCol].toString() : 'Sin nombre',
          cantidad: cantidad,
          descripcion: fila[descripcionCol] ? fila[descripcionCol].toString() : 'Sin descripción',
          costo: Number(fila[costoCol]) || 0,
          precio: Number(fila[precioCol]) || 0,
          ubicacion: ubicacion,
          fechaHora: fila[fechaCol] ? fila[fechaCol].toString() : 'Sin fecha'
        });
      }
    }

    if (coincidencias.length === 0) {
      Logger.log(`⚠️ No se encontró el código ${codigoNormalizado} en inventario`);
      return {
        success: false,
        codigo: codigo,
        coincidencias: [],
        totalCantidad: 0,
        totalUbicaciones: 0,
        mensaje: `⚠️ No se encontró el producto con código "${codigo}" en el inventario. Verifique que el producto haya sido registrado con entrada.`
      };
    }

    Logger.log(`✅ Total encontrado: ${coincidencias.length} ubicaciones, ${totalCantidad} unidades`);

    // ⚠️ AQUÍ ESTÁ LA CORRECCIÓN - AGREGAR success: true
    return {
      success: true,  // ← ESTO FALTABA
      codigo: codigo,
      coincidencias: coincidencias,
      totalCantidad: totalCantidad,
      totalUbicaciones: coincidencias.length
    };

  } catch (error) {
    console.error("❌ Error en buscarEnInventarioPorUbicacion:", error);
    Logger.log("Error stack: " + error.stack);
    return { 
      success: false,
      error: `Error al buscar: ${error.message}` 
    };
  }
}

function obtenerStock() {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const prodSheet = ss.getSheetByName(HOJA_PRODUCTOS);
    
    if (!prodSheet) {
      throw new Error(`La hoja '${HOJA_PRODUCTOS}' no existe.`);
    }
    
    const productos = prodSheet.getDataRange().getValues();
    
    if (productos.length <= 1) {
      return [];
    }
    
    const stock = [];
    
    for (let i = 1; i < productos.length; i++) {
      const [codigo, nombre, unidad, grupo, stockMin, precio] = productos[i];
      if (codigo && nombre) {
        const cantidad = calcularStock(codigo);
        stock.push({
          codigo: codigo.toString(),
          nombre: nombre.toString(),
          unidad: unidad || "Unidades",
          grupo: grupo || "General",
          stockMin: Math.max(0, parseInt(stockMin) || 0),
          cantidad: cantidad,
          precio: parseFloat(precio) || 0
        });
      }
    }
    
    return stock.sort((a, b) => a.nombre.localeCompare(b.nombre));
  } catch (error) {
    console.error("Error en obtenerStock:", error);
    return [];
  }
}

function calcularStock(codigo) {
  try {
    if (!codigo) return 0;
    
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const movSheet = ss.getSheetByName(HOJA_MOVIMIENTOS);
    
    if (!movSheet) {
      return 0;
    }
    
    const movimientos = movSheet.getDataRange().getValues();
    let cantidad = 0;
    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    
    for (let i = 1; i < movimientos.length; i++) {
      const [cod, fecha, tipo, cant] = movimientos[i];
      if (cod && cod.toString().trim().toUpperCase() === codigoNormalizado) {
        const valor = parseFloat(cant) || 0;
        const tipoMovimiento = tipo.toString().toUpperCase();
        
        switch (tipoMovimiento) {
          case TIPOS_MOVIMIENTO.INGRESO:
          case TIPOS_MOVIMIENTO.AJUSTE_POSITIVO:
            cantidad += valor;
            break;
          case TIPOS_MOVIMIENTO.SALIDA:
          case TIPOS_MOVIMIENTO.AJUSTE_NEGATIVO:
          case TIPOS_MOVIMIENTO.VENTA:
            cantidad -= valor;
            break;
          case TIPOS_MOVIMIENTO.AJUSTE:
            cantidad += valor;
            break;
        }
      }
    }
    
    return Math.max(0, Math.round(cantidad * 100) / 100);
  } catch (error) {
    console.error("Error en calcularStock:", error);
    return 0;
  }
}

/**
 * Calcula el stock real de un producto sumando las cantidades de todas sus
 * ubicaciones en la hoja Inventario (fuente de verdad).
 * @param {string} codigo - Código del producto
 * @returns {number} Stock total real del producto
 */
function calcularStockDesdeInventario(codigo) {
  try {
    if (!codigo) return 0;
    
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    
    if (!hojaInv) return 0;
    
    const datos = hojaInv.getDataRange().getValues();
    if (datos.length <= 1) return 0;
    
    // Mapear headers
    const headers = datos[0];
    const colIndex = {};
    headers.forEach(function(h, i) {
      if (h) colIndex[h.toString().toLowerCase().trim()] = i;
    });
    
    const codigoCol = colIndex['codigo unico del producto'];
    const cantidadCol = colIndex['cantidad de entrada del producto'];
    
    if (codigoCol === undefined || cantidadCol === undefined) return 0;
    
    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    let total = 0;
    
    for (let i = 1; i < datos.length; i++) {
      const codInv = datos[i][codigoCol] ? datos[i][codigoCol].toString().trim().toUpperCase() : '';
      if (codInv === codigoNormalizado) {
        total += Number(datos[i][cantidadCol]) || 0;
      }
    }
    
    return Math.max(0, Math.round(total * 100) / 100);
  } catch (error) {
    console.error("Error en calcularStockDesdeInventario:", error);
    return 0;
  }
}

function verificarStockEnUbicacion(codigo, ubicacion) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    
    if (!hojaInv) return 0;
    
    const datos = hojaInv.getDataRange().getValues();
    const headers = datos[0];
    const colIndex = {};
    
    headers.forEach((h, i) => {
      colIndex[h.toString().toLowerCase().trim()] = i;
    });
    
    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    const ubicacionNormalizada = ubicacion.toString().trim();
    
    for (let i = 1; i < datos.length; i++) {
      const codInv = datos[i][colIndex['codigo unico del producto']]?.toString().trim().toUpperCase();
      const ubInv = datos[i][colIndex['ubicacion del producto']]?.toString().trim();
      
      if (codInv === codigoNormalizado && ubInv === ubicacionNormalizada) {
        return Number(datos[i][colIndex['cantidad de entrada del producto']]) || 0;
      }
    }
    
    return 0;
  } catch (error) {
    console.error("Error en verificarStockEnUbicacion:", error);
    return 0;
  }
}

function descontarDeInventario(codigo, cantidad, ubicacion) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    
    if (!hojaInv) {
      return { success: false, message: "❌ La hoja de inventario no existe." };
    }
    
    const datos = hojaInv.getDataRange().getValues();
    const headers = datos[0];
    const colIndex = {};
    
    headers.forEach((h, i) => {
      colIndex[h.toString().toLowerCase().trim()] = i + 1;
    });
    
    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    const ubicacionNormalizada = ubicacion.toString().trim();
    
    for (let i = 1; i < datos.length; i++) {
      const codInv = datos[i][colIndex['codigo unico del producto'] - 1]?.toString().trim().toUpperCase();
      const ubInv = datos[i][colIndex['ubicacion del producto'] - 1]?.toString().trim();
      
      if (codInv === codigoNormalizado && ubInv === ubicacionNormalizada) {
        const fila = i + 1;
        const stockActual = Number(hojaInv.getRange(fila, colIndex['cantidad de entrada del producto']).getValue()) || 0;
        const nuevoStock = stockActual - cantidad;
        
        if (nuevoStock < 0) {
          return { success: false, message: `❌ Stock insuficiente en ${ubicacion}` };
        }
        
        hojaInv.getRange(fila, colIndex['cantidad de entrada del producto']).setValue(nuevoStock);
        hojaInv.getRange(fila, colIndex['fecha y hora']).setValue(new Date());
        
        Logger.log(`✅ Descontado ${cantidad} de ${codigo} en ${ubicacion}. Nuevo stock: ${nuevoStock}`);
        return { success: true };
      }
    }
    
    return { success: false, message: `❌ Producto ${codigo} no encontrado en ${ubicacion}` };
  } catch (error) {
    console.error("Error en descontarDeInventario:", error);
    return { success: false, message: `❌ Error: ${error.message}` };
  }
}

function obtenerUbicaciones() {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    
    // Ubicaciones predeterminadas del sistema
    const ubicacionesPredeterminadas = ["Casa Luden", "Casa Jean", "Casa Dylan"];
    
    if (!hojaInv) {
      return ubicacionesPredeterminadas;
    }
    
    const datos = hojaInv.getDataRange().getValues();
    const ubicaciones = new Set();
    
    // Agregar primero las ubicaciones predeterminadas
    ubicacionesPredeterminadas.forEach(ub => ubicaciones.add(ub));
    
    if (datos.length > 1) {
      const headers = datos[0];
      const colIndex = {};
      headers.forEach((h, i) => {
        colIndex[h.toString().toLowerCase().trim()] = i;
      });
      
      const ubicacionCol = colIndex['ubicacion del producto'];
      
      if (ubicacionCol !== undefined) {
        for (let i = 1; i < datos.length; i++) {
          if (datos[i][ubicacionCol] && datos[i][ubicacionCol].toString().trim()) {
            ubicaciones.add(datos[i][ubicacionCol].toString().trim());
          }
        }
      }
    }
    
    const ubicacionesArray = Array.from(ubicaciones).sort();
    
    Logger.log(`✅ Ubicaciones disponibles: ${ubicacionesArray.join(', ')}`);
    
    return ubicacionesArray;
  } catch (error) {
    console.error("Error en obtenerUbicaciones:", error);
    return ["Casa Luden", "Casa Jean", "Casa Dylan"];
  }
}

/**
 * Procesa una transferencia de stock entre dos ubicaciones
 * @param {Object} datos - {codigo, cantidad, ubicacionOrigen, ubicacionDestino, fecha, observaciones}
 * @returns {Object} {success: boolean, message: string}
 */
function procesarTransferenciaEntreUbicaciones(datos) {
  try {
    // Validaciones básicas
    if (!datos.codigo || !datos.cantidad || !datos.ubicacionOrigen || !datos.ubicacionDestino) {
      return {
        success: false,
        message: "❌ Todos los campos son obligatorios: código, cantidad, ubicación origen y destino."
      };
    }

    const codigo = datos.codigo.toString().trim().toUpperCase();
    const cantidad = parseFloat(datos.cantidad);
    const ubicacionOrigen = datos.ubicacionOrigen.toString().trim();
    const ubicacionDestino = datos.ubicacionDestino.toString().trim();
    const observaciones = datos.observaciones ? datos.observaciones.toString().trim() : "";
    const fecha = datos.fecha || new Date();

    // Validar que las ubicaciones sean diferentes
    if (ubicacionOrigen === ubicacionDestino) {
      return {
        success: false,
        message: "❌ La ubicación de origen y destino deben ser diferentes."
      };
    }

    // Validar cantidad positiva
    if (cantidad <= 0) {
      return {
        success: false,
        message: "❌ La cantidad debe ser mayor a cero."
      };
    }

    Logger.log(`🔄 Iniciando transferencia: ${cantidad} unidades de ${codigo} desde ${ubicacionOrigen} hacia ${ubicacionDestino}`);

    // Verificar que el producto existe
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaProductos = ss.getSheetByName(HOJA_PRODUCTOS);
    
    if (!hojaProductos) {
      return {
        success: false,
        message: "❌ La hoja de productos no existe. Inicialice el sistema primero."
      };
    }

    const datosProductos = hojaProductos.getDataRange().getValues();
    let productoExiste = false;
    let nombreProducto = "";

    for (let i = 1; i < datosProductos.length; i++) {
      if (datosProductos[i][0] && datosProductos[i][0].toString().trim().toUpperCase() === codigo) {
        productoExiste = true;
        nombreProducto = datosProductos[i][1] || "";
        break;
      }
    }

    if (!productoExiste) {
      return {
        success: false,
        message: `❌ El producto con código "${codigo}" no existe en el catálogo.`
      };
    }

    // Verificar stock en ubicación origen
    const stockOrigen = verificarStockEnUbicacion(codigo, ubicacionOrigen);
    
    if (stockOrigen < cantidad) {
      return {
        success: false,
        message: `❌ Stock insuficiente en ${ubicacionOrigen}. Disponible: ${stockOrigen}, Solicitado: ${cantidad}`
      };
    }

    Logger.log(`✅ Stock verificado en origen: ${stockOrigen} unidades disponibles`);

    // EJECUTAR TRANSFERENCIA
    
    // 1. Descontar de ubicación origen
    const resultadoDescuento = descontarDeInventario(codigo, cantidad, ubicacionOrigen);
    
    if (!resultadoDescuento.success) {
      return {
        success: false,
        message: resultadoDescuento.message
      };
    }

    Logger.log(`✅ Descontado de ${ubicacionOrigen}`);

    // 2. Sumar a ubicación destino
    const resultadoSuma = sumarAInventario(codigo, cantidad, ubicacionDestino, nombreProducto);
    
    if (!resultadoSuma.success) {
      // Rollback: devolver el stock al origen
      Logger.log("⚠️ Error al sumar a destino. Realizando rollback...");
      sumarAInventario(codigo, cantidad, ubicacionOrigen, nombreProducto);
      
      return {
        success: false,
        message: `❌ Error al transferir a ${ubicacionDestino}. Se ha revertido la operación.`
      };
    }

    Logger.log(`✅ Sumado a ${ubicacionDestino}`);

    // 3. Registrar movimiento de transferencia
    const observacionesCompletas = `Transferencia de ${ubicacionOrigen} → ${ubicacionDestino}. ${observaciones}`;
    
    const resultadoMovimiento = registrarMovimiento({
      codigo: codigo,
      fecha: typeof fecha === 'string' ? fecha : Utilities.formatDate(fecha, Session.getScriptTimeZone(), "yyyy-MM-dd"),
      tipo: TIPOS_MOVIMIENTO.TRANSFERENCIA,
      cantidad: cantidad,
      ubicacion: `${ubicacionOrigen} → ${ubicacionDestino}`,
      observaciones: observacionesCompletas
    });

    if (!resultadoMovimiento.includes("correctamente")) {
      Logger.log("⚠️ Advertencia: El movimiento no se registró correctamente, pero la transferencia física se completó.");
    }

    Logger.log(`✅ Transferencia completada exitosamente`);

    return {
      success: true,
      message: `✅ Transferencia exitosa: ${cantidad} unidades de "${nombreProducto}" movidas desde ${ubicacionOrigen} a ${ubicacionDestino}.`
    };

  } catch (error) {
    console.error("❌ Error en procesarTransferenciaEntreUbicaciones:", error);
    Logger.log("Error stack: " + error.stack);
    return {
      success: false,
      message: `❌ Error al procesar transferencia: ${error.message}`
    };
  }
}

/**
 * Suma stock a una ubicación específica en Inventario
 * Si no existe la entrada, la crea
 * @param {string} codigo - Código del producto
 * @param {number} cantidad - Cantidad a sumar
 * @param {string} ubicacion - Ubicación destino
 * @param {string} nombreProducto - Nombre del producto (para crear entrada si no existe)
 * @returns {Object} {success: boolean, message: string}
 */
function sumarAInventario(codigo, cantidad, ubicacion, nombreProducto) {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    const hojaProductos = ss.getSheetByName(HOJA_PRODUCTOS);
    
    if (!hojaInv) {
      return { success: false, message: "❌ La hoja de inventario no existe." };
    }

    const datos = hojaInv.getDataRange().getValues();
    const headers = datos[0];
    const colIndex = {};
    
    headers.forEach((h, i) => {
      colIndex[h.toString().toLowerCase().trim()] = i + 1;
    });

    const codigoNormalizado = codigo.toString().trim().toUpperCase();
    const ubicacionNormalizada = ubicacion.toString().trim();
    let filaEncontrada = null;

    // Buscar si ya existe la entrada para este producto en esta ubicación
    for (let i = 1; i < datos.length; i++) {
      const codInv = datos[i][colIndex['codigo unico del producto'] - 1]?.toString().trim().toUpperCase();
      const ubInv = datos[i][colIndex['ubicacion del producto'] - 1]?.toString().trim();
      
      if (codInv === codigoNormalizado && ubInv === ubicacionNormalizada) {
        filaEncontrada = i + 1;
        break;
      }
    }

    if (filaEncontrada) {
      // Ya existe: sumar a la cantidad actual
      const stockActual = Number(hojaInv.getRange(filaEncontrada, colIndex['cantidad de entrada del producto']).getValue()) || 0;
      const nuevoStock = stockActual + cantidad;
      
      hojaInv.getRange(filaEncontrada, colIndex['cantidad de entrada del producto']).setValue(nuevoStock);
      hojaInv.getRange(filaEncontrada, colIndex['fecha y hora']).setValue(new Date());
      
      Logger.log(`✅ Sumado ${cantidad} a ${ubicacion}. Stock anterior: ${stockActual}, nuevo: ${nuevoStock}`);
      
    } else {
      // No existe: crear nueva entrada
      const nuevaFila = hojaInv.getLastRow() + 1;
      
      // Obtener datos adicionales del producto (precio, costo, etc.)
      let precio = 0, costo = 0, descripcion = "";
      const datosProductos = hojaProductos.getDataRange().getValues();
      
      for (let i = 1; i < datosProductos.length; i++) {
        if (datosProductos[i][0] && datosProductos[i][0].toString().trim().toUpperCase() === codigoNormalizado) {
          precio = Number(datosProductos[i][5]) || 0;
          break;
        }
      }
      
      hojaInv.getRange(nuevaFila, colIndex['codigo unico del producto']).setValue(codigoNormalizado);
      hojaInv.getRange(nuevaFila, colIndex['nombre del producto']).setValue(nombreProducto);
      hojaInv.getRange(nuevaFila, colIndex['cantidad de entrada del producto']).setValue(cantidad);
      hojaInv.getRange(nuevaFila, colIndex['precio']).setValue(precio);
      hojaInv.getRange(nuevaFila, colIndex['costo']).setValue(costo);
      hojaInv.getRange(nuevaFila, colIndex['ubicacion del producto']).setValue(ubicacionNormalizada);
      hojaInv.getRange(nuevaFila, colIndex['descripción del producto']).setValue(descripcion);
      hojaInv.getRange(nuevaFila, colIndex['fecha y hora']).setValue(new Date());
      
      Logger.log(`✅ Nueva entrada creada en ${ubicacion} con ${cantidad} unidades`);
    }
    
    return { success: true };
    
  } catch (error) {
    console.error("Error en sumarAInventario:", error);
    return { success: false, message: `❌ Error: ${error.message}` };
  }
}

/**
 * Obtiene el stock agrupado por producto con desglose por ubicación.
 * Lee la hoja Inventario (una fila por producto-ubicación) y agrupa por código,
 * sumando las cantidades de cada ubicación para calcular el Total.
 * @returns {Object} { ubicaciones: string[], productos: Object[] }
 */
function obtenerStockPorUbicacion() {
  try {
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const hojaInv = ss.getSheetByName(HOJA_INVENTARIO);
    const hojaProductos = ss.getSheetByName(HOJA_PRODUCTOS);

    if (!hojaInv || !hojaProductos) {
      return { ubicaciones: [], productos: [] };
    }

    // Obtener todas las ubicaciones disponibles
    const ubicacionesDisponibles = obtenerUbicaciones();

    // Leer datos de Inventario
    const datosInv = hojaInv.getDataRange().getValues();
    if (datosInv.length <= 1) {
      return { ubicaciones: ubicacionesDisponibles, productos: [] };
    }

    // Mapear headers de Inventario
    const headersInv = datosInv[0];
    const colInv = {};
    headersInv.forEach(function(h, i) {
      if (h) colInv[h.toString().toLowerCase().trim()] = i;
    });

    // Leer catálogo de productos para obtener grupo, unidad, stockMin
    const datosProductos = hojaProductos.getDataRange().getValues();
    const catalogoProductos = {};
    for (var p = 1; p < datosProductos.length; p++) {
      var codProd = datosProductos[p][0];
      if (codProd) {
        catalogoProductos[codProd.toString().trim().toUpperCase()] = {
          nombre: datosProductos[p][1] || "",
          unidad: datosProductos[p][2] || "Unidades",
          grupo: datosProductos[p][3] || "General",
          stockMin: Math.max(0, parseInt(datosProductos[p][4]) || 0),
          precio: parseFloat(datosProductos[p][5]) || 0
        };
      }
    }

    // Agrupar datos de inventario por código de producto
    var productosAgrupados = {};

    for (var i = 1; i < datosInv.length; i++) {
      var fila = datosInv[i];
      var codigoCol = colInv['codigo unico del producto'];
      var cantidadCol = colInv['cantidad de entrada del producto'];
      var ubicacionCol = colInv['ubicacion del producto'];
      var precioCol = colInv['precio'];
      var costoCol = colInv['costo'];

      if (codigoCol === undefined || cantidadCol === undefined || ubicacionCol === undefined) {
        continue;
      }

      var codigo = fila[codigoCol] ? fila[codigoCol].toString().trim().toUpperCase() : '';
      if (!codigo) continue;

      var cantidad = Number(fila[cantidadCol]) || 0;
      var ubicacion = fila[ubicacionCol] ? fila[ubicacionCol].toString().trim() : 'Sin ubicación';
      var precio = precioCol !== undefined ? (Number(fila[precioCol]) || 0) : 0;
      var costo = costoCol !== undefined ? (Number(fila[costoCol]) || 0) : 0;

      if (!productosAgrupados[codigo]) {
        var infoCatalogo = catalogoProductos[codigo] || {};
        productosAgrupados[codigo] = {
          codigo: codigo,
          nombre: infoCatalogo.nombre || (fila[colInv['nombre del producto']] ? fila[colInv['nombre del producto']].toString() : ''),
          grupo: infoCatalogo.grupo || 'General',
          unidad: infoCatalogo.unidad || 'Unidades',
          stockMin: infoCatalogo.stockMin || 0,
          precio: infoCatalogo.precio || precio,
          costo: costo,
          ubicaciones: {},
          total: 0
        };
      }

      // Sumar cantidad a la ubicación correspondiente
      productosAgrupados[codigo].ubicaciones[ubicacion] = 
        (Number(productosAgrupados[codigo].ubicaciones[ubicacion]) || 0) + cantidad;
    }

    // Calcular el total como la suma estricta de todas las ubicaciones
    var resultado = [];
    var codigos = Object.keys(productosAgrupados);
    for (var j = 0; j < codigos.length; j++) {
      var prod = productosAgrupados[codigos[j]];
      var totalCalculado = 0;
      var ubiKeys = Object.keys(prod.ubicaciones);
      for (var k = 0; k < ubiKeys.length; k++) {
        totalCalculado += Number(prod.ubicaciones[ubiKeys[k]]) || 0;
      }
      prod.total = totalCalculado;
      resultado.push(prod);
    }

    // Ordenar por nombre
    resultado.sort(function(a, b) {
      return a.nombre.localeCompare(b.nombre);
    });

    Logger.log("✅ obtenerStockPorUbicacion: " + resultado.length + " productos agrupados, " + ubicacionesDisponibles.length + " ubicaciones");

    return {
      ubicaciones: ubicacionesDisponibles,
      productos: resultado
    };

  } catch (error) {
    console.error("Error en obtenerStockPorUbicacion:", error);
    return { ubicaciones: [], productos: [] };
  }
}

function registrarProducto(producto) {
  try {
    if (!producto || !producto.codigo || !producto.nombre) {
      return "Datos del producto incompletos. Código y nombre son obligatorios.";
    }

    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    const sheet = ss.getSheetByName(HOJA_PRODUCTOS);
    
    if (!sheet) {
      throw new Error(`La hoja '${HOJA_PRODUCTOS}' no existe. Inicialice el sistema primero.`);
    }
    
    if (!sheet.getLastRow()) {
      sheet.getRange(1, 1, 1, 7).setValues([["Código", "Nombre", "Unidad", "Grupo", "Stock Mínimo", "Precio", "Fecha Creación"]]);
      sheet.getRange(1, 1, 1, 7).setBackground("#5DADE2").setFontColor("white").setFontWeight("bold");
    }
    
    const datos = sheet.getDataRange().getValues();
    const codigoNormalizado = producto.codigo.toString().trim().toUpperCase();
    
    for (let i = 1; i < datos.length; i++) {
      if (datos[i][0] && datos[i][0].toString().trim().toUpperCase() === codigoNormalizado) {
        return "Ya existe un producto con este código.";
      }
    }
    
    const nombre = producto.nombre.toString().trim();
    const unidad = producto.unidad || "Unidades";
    const grupo = producto.grupo || "General";
    const stockMin = Math.max(0, parseInt(producto.stockMin) || 0);
    const precio = Math.max(0, parseFloat(producto.precio) || 0);
    
    if (nombre.length < 2) {
      return "El nombre del producto debe tener al menos 2 caracteres.";
    }
    
    sheet.appendRow([
      codigoNormalizado,
      nombre,
      unidad,
      grupo,
      stockMin,
      precio,
      new Date()
    ]);
    
    return "Producto registrado correctamente.";
  } catch (error) {
    console.error("Error en registrarProducto:", error);
    return `Error al registrar producto: ${error.message}`;
  }
}

function buscarProductoPorCodigo(codigo) {
